        test('can cancel a running job by reservation_id and allow the next job to run', async function () {
            let jobStartedResolve: (() => void) | undefined;
            let jobFinishedResolve: (() => void) | undefined;
            let releaseJobResolve: (() => void) | undefined;
            let jobStarted = new Promise<void>((resolve) => {
                jobStartedResolve = resolve;
            });
            let jobFinished = new Promise<void>((resolve) => {
                jobFinishedResolve = resolve;
            });
            let releaseJob = new Promise<void>((resolve) => {
                releaseJobResolve = resolve;
            });
            let events: string[] = [];
            context.runner.register('blocking-job', async ({ jobNum }: {
                jobNum: number;
            }) => {
                events.push(`job${jobNum} start`);
                if (jobNum === 1) {
                    jobStartedResolve?.();
                    await releaseJob;
                }
                events.push(`job${jobNum} finish`);
                if (jobNum === 1) {
                    jobFinishedResolve?.();
                }
                return jobNum;
            });
            let job1 = await context.publisher.publish({
                jobType: 'blocking-job',
                concurrencyGroup: 'grafana-cancel-group',
                timeout: 30,
                args: { jobNum: 1 },
            });
            let job1Outcome = job1.done.then((result) => ({ outcome: 'resolved' as const, result }), (error) => ({ outcome: 'rejected' as const, error }));
            await jobStarted;
            let [reservation] = await context.dbAdapter.execute(`SELECT id FROM job_reservations WHERE job_id = ${job1.id} AND completed_at IS NULL`);
            let reservationId = reservation?.id;
            expect(reservationId).toBeTruthy();
            let response = await context.request2
                .get(`/_grafana-complete-job?authHeader=${grafanaSecret}&reservation_id=${reservationId}`)
                .set('Content-Type', 'application/json');
            expect(response.status).toBe(204);
            let reservations = await context.dbAdapter.execute(`SELECT id FROM job_reservations WHERE job_id = ${job1.id} AND completed_at IS NULL`);
            expect(reservations.length).toBe(0);
            let adapter2 = new PgAdapter();
            let runner2 = new PgQueueRunner({
                adapter: adapter2,
                workerId: 'test-worker-2',
            });
            runner2.register('blocking-job', async ({ jobNum }: {
                jobNum: number;
            }) => {
                events.push(`job${jobNum} start`);
                events.push(`job${jobNum} finish`);
                return jobNum;
            });
            await runner2.start();
            try {
                let job2 = await context.publisher.publish({
                    jobType: 'blocking-job',
                    concurrencyGroup: 'grafana-cancel-group',
                    timeout: 30,
                    args: { jobNum: 2 },
                });
                let job2Result = await job2.done;
                expect(job2Result).toBe(2);
            }
            finally {
                releaseJobResolve?.();
                await jobFinished;
                await runner2.destroy();
                await adapter2.close();
            }
            let outcome = await job1Outcome;
            expect(outcome.outcome).toBe('rejected');
            if (outcome.outcome === 'rejected') {
                expect(outcome.error).toEqual({
                    status: 418,
                    message: 'User initiated job cancellation',
                });
            }
            else {
                expect(false).toBeTruthy();
            }
            expect(events).toEqual([
                'job1 start',
                'job2 start',
                'job2 finish',
                'job1 finish',
            ]);
        });
